import socket,sys,time
s=socket.socket(); s.connect(('127.0.0.1',6665)); s.settimeout(2)
data=b''
end=time.time()+float(sys.argv[1] if len(sys.argv)>1 else 20)
while time.time()<end:
    try:
        b=s.recv(4096)
        if b: data+=b
    except socket.timeout:
        pass
# strip telnet IAC sequences crudely
out=bytearray(); i=0
while i<len(data):
    if data[i]==255:
        i+=3; continue
    out.append(data[i]); i+=1
sys.stdout.write(out.decode('latin1'))
EOF
